func pageHref(search models.SoldierSearch, page int) templ.SafeURL {
	return templ.SafeURL(pageRequestURL(search, page))
}

func pageRequestURL(search models.SoldierSearch, page int) string {
	params := searchParams(search)
	params.Set("page", fmt.Sprintf("%d", page))
	if search.Mode == "advanced" {
		return "/soldiers/search/advanced?" + params.Encode()
	}
	return "/soldiers/search?" + params.Encode()
}

func searchParams(search models.SoldierSearch) url.Values {
	values := url.Values{}
	if search.Mode == "advanced" {
		if strings.TrimSpace(search.DisplayID) != "" {
			values.Set("display_id", search.DisplayID)
		}
		if strings.TrimSpace(search.FirstName) != "" {
			values.Set("first_name", search.FirstName)
		}
		if strings.TrimSpace(search.MiddleName) != "" {
			values.Set("middle_name", search.MiddleName)
		}
		if strings.TrimSpace(search.LastName) != "" {
			values.Set("last_name", search.LastName)
		}
		if strings.TrimSpace(search.MaidenName) != "" {
			values.Set("maiden_name", search.MaidenName)
		}
		if strings.TrimSpace(search.Rank) != "" {
			values.Set("rank", search.Rank)
		}
		if strings.TrimSpace(search.RankIn) != "" {
			values.Set("rank_in", search.RankIn)
		}
		if strings.TrimSpace(search.RankOut) != "" {
			values.Set("rank_out", search.RankOut)
		}
		if strings.TrimSpace(search.Unit) != "" {
			values.Set("unit", search.Unit)
		}
		if strings.TrimSpace(search.RecordType) != "" {
			values.Set("record_type", search.RecordType)
		}
		if strings.TrimSpace(search.PensionState) != "" {
			values.Set("pension_state", search.PensionState)
		}
		if strings.TrimSpace(search.ConfederateHomeStatus) != "" {
			values.Set("confederate_home_status", search.ConfederateHomeStatus)
		}
		if strings.TrimSpace(search.ConfederateHomeName) != "" {
			values.Set("confederate_home_name", search.ConfederateHomeName)
		}
		if strings.TrimSpace(search.BuriedIn) != "" {
			values.Set("buried_in", search.BuriedIn)
		}
		if strings.TrimSpace(search.BirthDate) != "" {
			values.Set("birth_date", search.BirthDate)
		}
		if strings.TrimSpace(search.BirthYear) != "" {
			values.Set("birth_year", search.BirthYear)
		}
		if strings.TrimSpace(search.BirthYearTo) != "" {
			values.Set("birth_year_to", search.BirthYearTo)
		}
		if strings.TrimSpace(search.DeathDate) != "" {
			values.Set("death_date", search.DeathDate)
		}
		if strings.TrimSpace(search.DeathYear) != "" {
			values.Set("death_year", search.DeathYear)
		}
		if strings.TrimSpace(search.DeathYearTo) != "" {
			values.Set("death_year_to", search.DeathYearTo)
		}
		if strings.TrimSpace(search.DeathMonth) != "" {
			values.Set("death_month", search.DeathMonth)
		}
		if strings.TrimSpace(search.DeathDay) != "" {
			values.Set("death_day", search.DeathDay)
		}
		return values
	}
	if search.Browse {
		values.Set("browse", "1")
	}
	if strings.TrimSpace(search.Query) != "" {
		values.Set("q", search.Query)
	}
	return values
}

func searchSummary(search models.SoldierSearch) string {
	if search.Mode != "advanced" {
		if search.Browse {
			return "Browse: alphabetical list"
		}
		if strings.TrimSpace(search.Query) == "" {
			return ""
		}
		return fmt.Sprintf("Search: %q", search.Query)
	}

	parts := []string{}
	if search.DisplayID != "" {
		parts = append(parts, "Record ID "+search.DisplayID)
	}
	if search.FirstName != "" {
		parts = append(parts, "First name "+search.FirstName)
	}
	if search.MiddleName != "" {
		parts = append(parts, "Middle name "+search.MiddleName)
	}
	if search.LastName != "" {
		parts = append(parts, "Last name "+search.LastName)
	}
	if search.MaidenName != "" {
		parts = append(parts, "Maiden name "+search.MaidenName)
	}
	if search.Rank != "" {
		parts = append(parts, "Rank "+search.Rank)
	}
	if search.RankIn != "" {
		parts = append(parts, "Rank in "+search.RankIn)
	}
	if search.RankOut != "" {
		parts = append(parts, "Rank out "+search.RankOut)
	}
	if search.Unit != "" {
		parts = append(parts, "Unit "+search.Unit)
	}
	if search.RecordType != "" {
		parts = append(parts, "Record type "+search.RecordType)
	}
	if search.PensionState != "" {
		parts = append(parts, "Pension state "+search.PensionState)
	}
	if search.ConfederateHomeStatus != "" {
		parts = append(parts, "Confederate home status "+search.ConfederateHomeStatus)
	}
	if search.ConfederateHomeName != "" {
		parts = append(parts, "Confederate home name "+search.ConfederateHomeName)
	}
	if search.BuriedIn != "" {
		parts = append(parts, "Buried in "+search.BuriedIn)
	}
	if search.BirthDate != "" {
		parts = append(parts, "Birth date "+search.BirthDate)
	}
	if search.BirthYear != "" && search.BirthYearTo != "" {
		parts = append(parts, "Birth year "+search.BirthYear+"-"+search.BirthYearTo)
	} else if search.BirthYear != "" {
		parts = append(parts, "Birth year "+search.BirthYear)
	} else if search.BirthYearTo != "" {
		parts = append(parts, "Birth year through "+search.BirthYearTo)
	}
	if search.DeathDate != "" {
		parts = append(parts, "Death date "+search.DeathDate)
	}
	if search.DeathYear != "" && search.DeathYearTo != "" {
		parts = append(parts, "Death year "+search.DeathYear+"-"+search.DeathYearTo)
	} else if search.DeathYear != "" {
		parts = append(parts, "Death year "+search.DeathYear)
	} else if search.DeathYearTo != "" {
		parts = append(parts, "Death year through "+search.DeathYearTo)
	}
	if search.DeathMonth != "" {
		parts = append(parts, "Death month "+search.DeathMonth)
	}
	if search.DeathDay != "" {
		parts = append(parts, "Death day "+search.DeathDay)
	}
	if len(parts) == 0 {
		return "Advanced search"
	}
	return "Advanced filters: " + strings.Join(parts, ", ")
}

func soldierFullName(s models.Soldier) string {
	return s.GetFullName()
}

func isSoldierEntry(s models.Soldier) bool {
	return strings.TrimSpace(s.EntryType) == "" || s.EntryType == "soldier"
}

func isWidowEntry(s models.Soldier) bool {
	return s.EntryType == "widow"
}

func entryBadgeLabel(s models.Soldier) string {
	switch s.EntryType {
	case "wife":
		return "Wife"
	case "widow":
		return "Widow"
	default:
		return "Soldier"
	}
}

func detailHeading(s models.Soldier) string {
	name := strings.TrimSpace(soldierFullName(s))
	if isSoldierEntry(s) {
		rank := strings.TrimSpace(detailDisplayRank(s))
		if rank == "" {
			return name
		}
		if name == "" {
			return rank
		}
		return rank + " " + name
	}
	if name != "" {
		return name
	}
	return entryBadgeLabel(s)
}

func detailSubheading(s models.Soldier) string {
	if isSoldierEntry(s) {
		return strings.TrimSpace(s.Unit)
	}
	if strings.TrimSpace(s.SpouseName) != "" {
		return "Married to " + strings.TrimSpace(s.SpouseName)
	}
	return strings.TrimSpace(s.MaidenName)
}

func detailDisplayRank(s models.Soldier) string {
	if trimmed := strings.TrimSpace(s.RankOut); trimmed != "" {
		return trimmed
	}
	if trimmed := strings.TrimSpace(s.Rank); trimmed != "" {
		return trimmed
	}
	return strings.TrimSpace(s.RankIn)
}

